import React, { useState, useEffect } from 'react';
import { db } from '../firebase';
import { collection, getDocs, doc, updateDoc } from 'firebase/firestore';
import { ArrowLeft, ShieldCheck, CheckCircle, XCircle, Clock, ExternalLink } from 'lucide-react';

function AdminDashboard({ onNavigate }) {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('Pending');

  useEffect(() => {
    fetchProjects();
  }, []);

  const fetchProjects = async () => {
    try {
      const querySnapshot = await getDocs(collection(db, "projects"));
      const projectsList = querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      setProjects(projectsList);
      setLoading(false);
    } catch (error) {
      console.error("Error fetching projects:", error);
      setLoading(false);
    }
  };

  const handleStatusChange = async (projectId, newStatus) => {
    try {
      const projectRef = doc(db, "projects", projectId);
      await updateDoc(projectRef, { status: newStatus });
      // Update local UI immediately
      setProjects(projects.map(p => p.id === projectId ? { ...p, status: newStatus } : p));
    } catch (error) {
      console.error("Error updating status:", error);
      alert("Failed to update status.");
    }
  };

  const filteredProjects = projects.filter(p => p.status === activeTab);

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-gray-100 font-sans pb-12">
      {/* 🎨 Premium Header */}
      <div className="bg-black/50 backdrop-blur-xl border-b border-white/10 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <button onClick={() => onNavigate('home')} className="p-2 rounded-full hover:bg-white/10 transition-colors text-gray-400 hover:text-white">
              <ArrowLeft className="w-6 h-6" />
            </button>
            <div>
              <h1 className="text-2xl font-bold text-white flex items-center gap-2">
                <ShieldCheck className="w-6 h-6 text-indigo-400" /> Admin Command Center
              </h1>
              <p className="text-xs text-gray-400">Manage NIMIT student submissions</p>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 mt-8">
        {/* 🎨 Custom Tabs */}
        <div className="flex gap-4 mb-8 border-b border-white/10 pb-4">
          {['Pending', 'Approved', 'Rejected'].map(tab => (
            <button 
              key={tab} 
              onClick={() => setActiveTab(tab)} 
              className={`px-6 py-2.5 rounded-xl font-bold text-sm transition-all flex items-center gap-2 ${activeTab === tab ? 'bg-indigo-600 text-white shadow-[0_0_15px_rgba(79,70,229,0.4)]' : 'bg-white/5 text-gray-400 hover:bg-white/10 hover:text-white'}`}
            >
              {tab === 'Pending' && <Clock className="w-4 h-4" />}
              {tab === 'Approved' && <CheckCircle className="w-4 h-4" />}
              {tab === 'Rejected' && <XCircle className="w-4 h-4" />}
              {tab} ({projects.filter(p => p.status === tab).length})
            </button>
          ))}
        </div>

        {/* 🎨 Dashboard Grid */}
        {loading ? (
          <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-500"></div></div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredProjects.map((project) => (
              <div key={project.id} className="bg-white/5 backdrop-blur-md border border-white/10 rounded-[1.5rem] p-5 flex flex-col hover:border-white/20 transition-all">
                <div className="flex justify-between items-start mb-4">
                  <div>
                    <h3 className="text-lg font-bold text-white">{project.title}</h3>
                    <p className="text-xs text-indigo-400 font-medium">{project.category}</p>
                  </div>
                  {project.liveDemoUrl && (
                    <a href={project.liveDemoUrl} target="_blank" rel="noopener noreferrer" className="p-2 bg-white/10 rounded-full hover:bg-white/20 transition text-white">
                      <ExternalLink className="w-4 h-4" />
                    </a>
                  )}
                </div>
                
                <p className="text-sm text-gray-400 mb-4 line-clamp-3 flex-1">{project.description}</p>
                
                <div className="text-xs text-gray-500 mb-4 bg-black/40 p-3 rounded-xl border border-white/5">
                  <p>👤 <span className="text-gray-300">{project.authorName}</span></p>
                  <p className="mt-1">✉️ {project.authorEmail}</p>
                </div>

                {/* 🔴 ACTION BUTTONS 🟢 */}
                {activeTab === 'Pending' && (
                  <div className="flex gap-3 mt-auto">
                    <button onClick={() => handleStatusChange(project.id, 'Approved')} className="flex-1 bg-green-500/20 text-green-400 border border-green-500/30 py-2.5 rounded-xl font-bold text-sm hover:bg-green-500 hover:text-white transition-all flex items-center justify-center gap-2">
                      <CheckCircle className="w-4 h-4" /> Approve
                    </button>
                    <button onClick={() => handleStatusChange(project.id, 'Rejected')} className="flex-1 bg-red-500/20 text-red-400 border border-red-500/30 py-2.5 rounded-xl font-bold text-sm hover:bg-red-500 hover:text-white transition-all flex items-center justify-center gap-2">
                      <XCircle className="w-4 h-4" /> Reject
                    </button>
                  </div>
                )}
                {activeTab !== 'Pending' && (
                  <button onClick={() => handleStatusChange(project.id, 'Pending')} className="w-full mt-auto bg-white/10 text-white border border-white/10 py-2.5 rounded-xl font-bold text-sm hover:bg-white/20 transition-all">
                    Move back to Pending
                  </button>
                )}
              </div>
            ))}
            {filteredProjects.length === 0 && (
              <div className="col-span-full text-center text-gray-500 py-20 bg-white/5 rounded-3xl border border-white/5">
                No {activeTab.toLowerCase()} projects found.
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

export default AdminDashboard;
